    <script>
        let autoCollapseTimer = null;

        function SafeGetValue(obj, path, defaultValue = "N/A") {
            let keys = Array.isArray(path) ? path : path.split('.');
            let current = obj;
            for (let i = 0; i < keys.length; i++) {
                if (current === undefined || current === null || typeof current !== 'object' || !current.hasOwnProperty(keys[i])) {
                    return defaultValue;
                }
                current = current[keys[i]];
            }
            if (current === undefined || current === null) {
                return defaultValue;
            }
            if (Array.isArray(current)) {
                if (current.length > 0) {
                    const actualValue = current[0];
                    if (typeof actualValue === 'boolean') {
                        return actualValue;
                    }
                    return String(actualValue);
                } else {
                    return defaultValue;
                }
            }
            if (typeof current === 'boolean') {
                return current;
            }
            return String(current);
        }

        // Hàm trích xuất giá trị mới đã sửa - phân biệt giá trị sa ngã và các biến khác
        function extractNewValue(rawValue, path, defaultValue = "N/A") {
            const fullValue = SafeGetValue({ temp: rawValue }, 'temp', defaultValue);
            let stringValue = String(fullValue).trim();

            // Kiểm tra xem có phải là biến giá trị sa ngã không (cần hiển thị đầy đủ)
            if (path.includes('.Giá trị sa ngã')) {
                return stringValue; // Giá trị sa ngã trả về trực tiếp nội dung đầy đủ, bao gồm cả chú thích
            }

            // Kiểm tra xem có phải là biến thời gian không (cần hiển thị đầy đủ)
            if (path === 'Thế giới.Thời gian hiện tại' || path === 'Thế giới.Ngày hiện tại') {
                return stringValue;
            }

            // Đối với các biến khác, loại bỏ chú thích và trích xuất giá trị mới
            // Trước tiên, loại bỏ phần chú thích ở cuối (xxx)
            const commentRegex = /\s*\([^)]*\)\s*$/;
            stringValue = stringValue.replace(commentRegex, '').trim();

            // Sau đó xử lý định dạng "giá trị cũ->giá trị mới"
            if (stringValue.includes('->')) {
                const arrowIndex = stringValue.lastIndexOf('->');
                const newValuePart = stringValue.substring(arrowIndex + 2).trim();
                return newValuePart;
            }

            // Nếu không có mũi tên, trả về trực tiếp giá trị đã xử lý
            return stringValue;
        }

        function updateProgressBar(barId, valueMainId, valueDescId, rawValueFromCharacterData, min, max, color, variablePath) {
            const progressBar = document.getElementById(barId);
            const valueMainDisplay = document.getElementById(valueMainId);
            const valueDescDisplay = document.getElementById(valueDescId);
            if (!valueMainDisplay) return;

            let displayString = extractNewValue(rawValueFromCharacterData, variablePath, String(min));
            let numericValue = min;

            // Đối với giá trị sa ngã, cần xử lý đặc biệt việc trích xuất số (trích xuất số từ định dạng MVU đầy đủ)
            if (variablePath.includes('.Giá trị sa ngã')) {
                // Hiển thị định dạng MVU đầy đủ
                valueMainDisplay.innerText = displayString;

                // Trích xuất số từ định dạng MVU để dùng cho thanh tiến trình
                // Khớp với newValue trong định dạng _.set('path', oldValue, newValue)
                const mvuMatch = displayString.match(/_.set\([^,]+,\s*[^,]+,\s*([0-9.]+)\)/);
                if (mvuMatch) {
                    numericValue = parseFloat(mvuMatch[1]);
                } else {
                    // Nếu không phải định dạng MVU, thử trích xuất số đầu tiên
                    const valueMatch = displayString.match(/(\d+(?:\.\d+)?)/);
                    if (valueMatch) {
                        numericValue = parseFloat(valueMatch[1]);
                    }
                }
            } else {
                valueMainDisplay.innerText = displayString;
                if (!isNaN(parseFloat(displayString))) {
                    numericValue = parseFloat(displayString);
                }
            }

            if (valueDescDisplay) {
                valueDescDisplay.innerText = `/${max}`;
            }

            if (progressBar) {
                numericValue = Math.max(min, Math.min(max, numericValue));
                const range = max - min;
                const percentage = range === 0 ? (numericValue >= max ? 100 : 0) : ((numericValue - min) / range) * 100;
                progressBar.style.width = `${Math.max(0, Math.min(100, percentage))}%`;
                if (color) {
                    progressBar.style.background = color;
                }
            }
        }

        function updateBooleanDisplay(mainId, indicatorId, value, variablePath) {
            const mainElement = document.getElementById(mainId);
            const indicatorElement = document.getElementById(indicatorId);

            // Trích xuất giá trị mới
            const newValue = extractNewValue(value, variablePath, value);

            if (mainElement) {
                if (typeof newValue === 'boolean') {
                    mainElement.innerText = newValue ? 'Có' : 'Không';
                } else if (typeof newValue === 'string') {
                    const lowerValue = newValue.toLowerCase();
                    const boolValue = lowerValue === 'true' || lowerValue === 'có' || lowerValue === 'yes' || lowerValue === 'đúng';
                    mainElement.innerText = boolValue ? 'Có' : 'Không';
                } else {
                    mainElement.innerText = String(newValue);
                }
            }

            if (indicatorElement) {
                let boolValue;
                if (typeof newValue === 'boolean') {
                    boolValue = newValue;
                } else if (typeof newValue === 'string') {
                    const lowerValue = newValue.toLowerCase();
                    boolValue = lowerValue === 'true' || lowerValue === 'có' || lowerValue === 'yes' || lowerValue === 'đúng';
                } else {
                    boolValue = Boolean(newValue);
                }

                indicatorElement.className = `boolean-indicator ${boolValue ? 'true' : 'false'}`;
            }
        }

        function updateSimpleDisplay(elementId, value, variablePath, defaultValue = "N/A") {
