        // Hàm chuyển đổi module đã sửa - đồng bộ hóa bắt buộc
        function toggleModule(element) {
            const content = element.nextElementSibling;
            const arrow = element.querySelector('.module-icon');
            const moduleTitle = element.querySelector('.module-title').innerText;

            const isExpanded = content.classList.toggle('expanded');
            element.classList.toggle('expanded', isExpanded);
            arrow.innerText = isExpanded ? '▲' : '▼';

            // Bắt buộc đồng bộ hóa tất cả các module cùng tên, bất kể trạng thái của container cha
            const allModuleHeaders = document.querySelectorAll('.module-header');
            allModuleHeaders.forEach(header => {
                if (header !== element) {
                    const otherModuleTitle = header.querySelector('.module-title').innerText;
                    if (otherModuleTitle === moduleTitle) {
                        const otherContent = header.nextElementSibling;
                        const otherArrow = header.querySelector('.module-icon');

                        // Bắt buộc thiết lập trạng thái, đồng bộ hóa vô điều kiện
                        if (isExpanded) {
                            otherContent.classList.add('expanded');
                            header.classList.add('expanded');
                            otherArrow.innerText = '▲';
                        } else {
                            otherContent.classList.remove('expanded');
                            header.classList.remove('expanded');
                            otherArrow.innerText = '▼';
                        }

                        // Đảm bảo container của nhân vật cha cũng được mở rộng (nếu cần hiển thị nội dung)
                        if (isExpanded) {
                            const parentCharacterContent = header.closest('.character-content');
                            const parentCharacterHeader = parentCharacterContent?.previousElementSibling;
                            if (parentCharacterContent && parentCharacterHeader) {
                                if (!parentCharacterContent.classList.contains('expanded')) {
                                    parentCharacterContent.classList.add('expanded');
                                    parentCharacterHeader.classList.add('expanded');
                                    const parentArrow = parentCharacterHeader.querySelector('.expand-icon');
                                    if (parentArrow) parentArrow.innerText = '▲';
                                }
                            }
                        }
                    }
                }
            });
        }

        function expandAll() {
            if (autoCollapseTimer) {
                clearTimeout(autoCollapseTimer);
            }

            document.querySelectorAll('.character-content, .module-content').forEach(content => {
                content.classList.add('expanded');
            });
            document.querySelectorAll('.character-header, .module-header').forEach(header => {
                header.classList.add('expanded');
                const arrow = header.querySelector('.expand-icon, .module-icon');
                if (arrow) arrow.innerText = '▲';
            });

            autoCollapseTimer = setTimeout(() => {
                collapseAll();
            }, 30000);
        }

        function collapseAll() {
            if (autoCollapseTimer) {
                clearTimeout(autoCollapseTimer);
                autoCollapseTimer = null;
            }

            document.querySelectorAll('.character-content, .module-content').forEach(content => {
                content.classList.remove('expanded');
            });
            document.querySelectorAll('.character-header, .module-header').forEach(header => {
                header.classList.remove('expanded');
                const arrow = header.querySelector('.expand-icon, .module-icon');
                if (arrow) arrow.innerText = '▼';
            });
        }

        function toggleTheme() {
            const currentTheme = document.documentElement.getAttribute('data-theme');
            const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
            document.documentElement.setAttribute('data-theme', newTheme);
            localStorage.setItem('theme-preference', newTheme);

            const button = document.querySelector('.theme-toggle');
            button.innerText = newTheme === 'dark' ? '☀️ Chuyển đổi chủ đề' : '🌙 Chuyển đổi chủ đề';
        }

        function initTheme() {
            const savedTheme = localStorage.getItem('theme-preference') || 'light';
            document.documentElement.setAttribute('data-theme', savedTheme);

            const button = document.querySelector('.theme-toggle');
            button.innerText = savedTheme === 'dark' ? '☀️ Chuyển đổi chủ đề' : '🌙 Chuyển đổi chủ đề';
        }

        // Chức năng cửa sổ modal ảnh đại diện
        function showAvatarModal(event, imageSrc, characterName) {
            event.stopPropagation(); // Ngăn chặn sự kiện nổi bọt, để không kích hoạt sự kiện click của phần tử cha

            const modal = document.getElementById('avatarModal');
            const modalImage = document.getElementById('modalImage');
            const modalTitle = document.getElementById('modalTitle');

            modalImage.src = imageSrc;
            modalTitle.innerText = characterName + ' Ảnh đại diện';
            modal.classList.add('show');

            // Ngăn body cuộn
            document.body.style.overflow = 'hidden';
        }

        function closeModal(event) {
            // Nếu click vào khu vực nội dung của cửa sổ modal, không đóng
            if (event && event.target.closest('.modal-content') && !event.target.classList.contains('modal-close')) {
                return;
            }

            const modal = document.getElementById('avatarModal');
            modal.classList.remove('show');

            // Khôi phục body cuộn
            document.body.style.overflow = '';
        }

        // Đóng cửa sổ modal bằng phím ESC
        document.addEventListener('keydown', function(event) {
            if (event.key === 'Escape') {
                closeModal();
            }
        });

        document.addEventListener('DOMContentLoaded', () => {
            initTheme();
            initDisplay();
        });
    </script>
</body>
</html>
