            --shadow-medium: rgba(139, 69, 139, 0.5);
            --accent-primary: #ff88b5;
            --accent-secondary: #e6a8d8;
            --gradient-start: #7a5980;
            --gradient-end: #5a3e5b;
            --hover-bg: #4a3a4b;
            --sparkle: #ffd4e5;
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
            font-family: 'Microsoft YaHei', sans-serif;
            color: var(--text-primary);
            padding: var(--spacing-l);
            transition: color 0.3s ease;
            -webkit-font-smoothing: antialiased;
        }

        #options-wrapper {
            max-width: 800px; /* ĐÃ THAY ĐỔI: Tăng chiều rộng từ 600px lên 800px */
            margin: 0 auto;
            position: relative;
        }

        .options-container {
            border-radius: var(--corner-radius);
            box-shadow: 0 8px 32px var(--shadow-light);
            backdrop-filter: blur(10px);
            border: 2px solid var(--border-color);
            overflow: hidden;
            background: var(--bg-secondary);
            position: relative;
            transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
        }

        .options-container::before {
            content: '✨';
            position: absolute;
            top: 10px;
            left: 10px;
            font-size: 20px;
            animation: sparkle 2s ease-in-out infinite;
        }

        .options-container::after {
            content: '💕';
            position: absolute;
            bottom: 10px;
            right: 10px;
            font-size: 20px;
            animation: float 3s ease-in-out infinite;
        }

        @keyframes sparkle {
            0%, 100% { transform: rotate(0deg) scale(1); opacity: 0.8; }
            50% { transform: rotate(180deg) scale(1.2); opacity: 1; }
        }

        @keyframes float {
            0%, 100% { transform: translateY(0px); }
            50% { transform: translateY(-10px); }
        }

        .options-container.removing {
            animation: removeContainer 0.4s cubic-bezier(0.4, 0, 0.2, 1) forwards;
        }

        @keyframes removeContainer {
            to {
                opacity: 0;
                transform: scale(0.95) translateY(-10px);
                filter: blur(10px);
            }
        }

        .options-header {
            display: flex;
            justify-content: center;
            align-items: center;
            padding: var(--spacing-m) var(--spacing-l);
            background: linear-gradient(135deg, var(--gradient-start), var(--gradient-end));
            border-bottom: 2px solid var(--border-color);
            position: relative;
        }

        .options-title {
            font-size: 20px; /* ĐÃ THAY ĐỔI: Tăng cỡ chữ tiêu đề */
            font-weight: 600;
            color: var(--text-primary);
            letter-spacing: 1px;
            text-align: center;
        }

        .theme-toggle {
            position: absolute;
            right: var(--spacing-l);
            background: var(--bg-primary);
            border: 2px solid var(--accent-secondary);
            border-radius: 999px;
            padding: var(--spacing-xs) var(--spacing-s);
            cursor: pointer;
            font-size: 14px;
            transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
        }

        .theme-toggle:hover {
            transform: translateY(-2px) rotate(180deg);
            box-shadow: 0 4px 16px var(--shadow-medium);
            background: var(--accent-secondary);
        }

        .options-grid {
            padding: var(--spacing-l);
            display: grid;
            grid-template-columns: 1fr;
            gap: var(--spacing-s);
        }

        @media (min-width: 480px) {
            .options-grid {
                grid-template-columns: 1fr 1fr;
            }
        }

        .option-item {
            background: linear-gradient(135deg, var(--bg-primary), var(--bg-secondary));
            border: 2px solid var(--border-color);
            border-radius: var(--corner-radius);
            padding: var(--spacing-m);
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            position: relative;
            overflow: hidden;
            text-align: center;
            font-weight: 500;
            font-size: 16px; /* ĐÃ THAY ĐỔI: Tăng cỡ chữ từ 14px lên 16px */
            color: var(--text-primary);
            white-space: pre-wrap;
            opacity: 0;
            animation: fadeIn 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
        }

        @keyframes fadeIn {
            from {
                opacity: 0;
                transform: translateY(20px) scale(0.9) rotate(-5deg);
            }
            to {
                opacity: 1;
                transform: translateY(0) scale(1) rotate(0deg);
            }
        }

        .option-item.sending {
            animation: sendEffect 0.5s cubic-bezier(0.4, 0, 0.2, 1) forwards;
        }

        @keyframes sendEffect {
            0% { transform: scale(1) rotate(0deg); }
            40% {
                transform: scale(1.15) rotate(5deg);
                background: var(--accent-primary);
                color: white;
                box-shadow: 0 0 30px var(--accent-primary);
            }
            100% {
                transform: scale(0) rotate(360deg);
                opacity: 0;
            }
        }

        .option-item:hover {
            background: var(--hover-bg);
            transform: translateY(-3px) scale(1.05);
            box-shadow: 0 6px 20px var(--shadow-medium);
            border-color: var(--accent-primary);
        }

        .option-item::before {
            content: '♡';
            position: absolute;
            top: 5px;
            right: 10px;
            color: var(--accent-secondary);
            opacity: 0;
            transition: all 0.3s ease;
        }

        .option-item:hover::before {
            opacity: 1;
            transform: scale(1.2);
        }

        .success-message {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%) scale(0.8);
            background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
            color: white;
            padding: 16px 32px;
            border-radius: 999px;
            font-weight: 600;
            box-shadow: 0 8px 32px var(--shadow-medium);
            opacity: 0;
            pointer-events: none;
            transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .success-message.show {
            opacity: 1;
            transform: translate(-50%, -50%) scale(1);
            animation: successPulse 1s cubic-bezier(0.4, 0, 0.2, 1);
        }

        @keyframes successPulse {
            0% { box-shadow: 0 0 0 0 var(--accent-primary); }
            50% { box-shadow: 0 0 0 20px transparent; }
            100% { box-shadow: 0 0 0 0 transparent; }
        }
    </style>
</head>
<body>
    <div id="options-wrapper">
        <div class="options-container" id="options-container">
            <div class="options-header">
                <div class="options-title">Tùy chọn trả lời nhanh</div>
                <div class="theme-toggle" onclick="toggleTheme()">🌸</div>
            </div>
            <div class="options-grid" id="options-grid">
            </div>
        </div>
    </div>

    <div class="success-message" id="success-message">Đã gửi 💕</div>

    <script>
        const triggerQuickReply = (text) => {
            if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${text}|/trigger`);
            } else {
                console.log('SillyTavern environment not detected. Would send:', text);
            }
        };

        function toggleTheme() {
            const body = document.body;
            const currentTheme = body.getAttribute('data-theme');
            const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
            body.setAttribute('data-theme', newTheme);
            localStorage.setItem('theme-girl', newTheme);
        }

        function removeOptionsContainer() {
            const container = document.getElementById('options-container');
            const wrapper = document.getElementById('options-wrapper');

            container.classList.add('removing');

            setTimeout(() => {
                wrapper.remove();
            }, 400);
        }

        function showSuccessMessage() {
            const message = document.getElementById('success-message');
            message.classList.add('show');

            setTimeout(() => {
                message.classList.remove('show');
            }, 1200);
        }

        function initTheme() {
            const savedTheme = localStorage.getItem('theme-girl') || 'light';
            document.body.setAttribute('data-theme', savedTheme);
        }

        function createOptions(optionsString) {
            const optionsGrid = document.getElementById('options-grid');
            optionsGrid.innerHTML = '';

            const options = optionsString.split('|').map(opt => opt.trim()).filter(opt => opt.length > 0);

            options.forEach((option, index) => {
                const optionElement = document.createElement('div');
                optionElement.className = 'option-item';

                if (option.length > 20) {
                    optionElement.style.fontSize = '14px'; /* Giảm nhẹ nếu văn bản quá dài */
                }

                optionElement.textContent = option;
                optionElement.style.animationDelay = `${index * 0.05}s`;
                optionsGrid.appendChild(optionElement);
            });
        }

        document.getElementById('options-grid').addEventListener('click', function(event) {
            const optionItem = event.target.closest('.option-item');
            if (!optionItem) return;

            optionItem.classList.add('sending');

            const optionText = optionItem.textContent.trim();
            triggerQuickReply(optionText);

            showSuccessMessage();

            setTimeout(() => {
                removeOptionsContainer();
            }, 500);
        });

        document.addEventListener('DOMContentLoaded', function() {
            initTheme();
            createOptions('$1');
        });
    </script>
</body>
</html>
